query getFirstRedirect($forceDisableCache: Boolean, $orgId: ID, $personId: ID, $redirectType: String) {
  firstRedirect(
    personId: $personId
    forceDisableCache: $forceDisableCache
    orgId: $orgId
    redirectType: $redirectType
  ) {
    description
    redirectId
    redirectUrl
  }
}

